39	__global__ void halton23_kernel(uint32_t n_elements, size_t base_idx, vec2* __restrict__ output) {
40		uint32_t i = blockIdx.x * blockDim.x + threadIdx.x;
41		if (i >= n_elements) {
42			return;
43		}
44	
45		output[i] = {halton<2>(base_idx + i), halton<3>(base_idx + i)};
46	}
