48	__global__ void sobol2_kernel(uint32_t n_elements, size_t base_idx, uint32_t seed, vec2* __restrict__ output) {
49		uint32_t i = blockIdx.x * blockDim.x + threadIdx.x;
50		if (i >= n_elements) {
51			return;
52		}
53	
54		output[i] = ld_random_val_2d(base_idx + i, seed);
55	}
