57	__global__ void zip_kernel(uint32_t n_elements, const float* __restrict__ in, vec2* __restrict__ output) {
58		uint32_t i = blockIdx.x * blockDim.x + threadIdx.x;
59		if (i >= n_elements) {
60			return;
61		}
62	
63		output[i] = {in[i], in[i + n_elements]};
