66	__global__ void stratify2_kernel(uint32_t n_elements, uint32_t log2_batch_size, vec2* __restrict__ inout) {
67		uint32_t i = blockIdx.x * blockDim.x + threadIdx.x;
68		if (i >= n_elements) {
69			return;
70		}
71	
72		uint32_t log2Size = log2_batch_size / 2;
73		uint32_t size = 1 << log2Size;
74	
75		uint32_t in_batch_index = i & ((1 << log2_batch_size) - 1);
76	
77		uint32_t x = in_batch_index & ((1 << log2Size) - 1);
78		uint32_t y = in_batch_index >> log2Size;
79	
80		vec2 val = inout[i];
81		inout[i] = {val.x / size + ((float)x / size), val.y / size + ((float)y / size)};
82	}
