84	__global__ void init_image_coords(
85		uint32_t sample_index,
86		vec2* __restrict__ positions,
87		float* __restrict__ depth_buffer,
88		ivec2 resolution,
89		float aspect,
90		vec2 focal_length,
91		mat4x3 camera_matrix,
92		vec2 screen_center,
93		vec3 parallax_shift,
94		bool snap_to_pixel_centers,
95		float plane_z,
96		float aperture_size,
97		Foveation foveation,
98		Buffer2DView<const uint8_t> hidden_area_mask,
99		Lens lens
100	) {
101		uint32_t x = threadIdx.x + blockDim.x * blockIdx.x;
102		uint32_t y = threadIdx.y + blockDim.y * blockIdx.y;
103	
104		if (x >= resolution.x || y >= resolution.y) {
105			return;
106		}
107	
108		// The image is displayed on the plane [0.5, 0.5, 0.5] + [X, Y, 0] to facilitate
109		// a top-down view by default, while permitting general camera movements (for
110		// motion vectors and code sharing with 3D tasks).
111		// Hence: generate rays and intersect that plane.
112		Ray ray = pixel_to_ray(
113			sample_index,
114			{(int)x, (int)y},
115			resolution,
116			focal_length,
117			camera_matrix,
118			screen_center,
119			parallax_shift,
120			snap_to_pixel_centers,
121			0.0f, // near distance
122			plane_z,
123			aperture_size,
124			foveation,
125			hidden_area_mask,
126			lens
127		);
128	
129		// Intersect the Z=0.5 plane
130		float t = ray.is_valid() ? (0.5f - ray.o.z) / ray.d.z : -1.0f;
131	
132		uint32_t idx = x + resolution.x * y;
133		if (t <= 0.0f) {
134			depth_buffer[idx] = MAX_DEPTH();
135			positions[idx] = -vec2(1.0f);
136			return;
137		}
138	
139		vec2 uv = ray(t).xy();
140	
141		// Flip from world coordinates where Y goes up to image coordinates where Y goes down.
142		// Also, multiply the x-axis by the image's aspect ratio to make it have the right proportions.
143		uv = (uv - 0.5f) * vec2{aspect, -1.0f} + 0.5f;
144	
145		depth_buffer[idx] = t;
146		positions[idx] = uv;
147	}
