149	__global__ void shade_kernel_image(
150		ivec2 resolution, const vec2* __restrict__ positions, const vec3* __restrict__ colors, vec4* __restrict__ frame_buffer, bool linear_colors
151	) {
152		uint32_t x = threadIdx.x + blockDim.x * blockIdx.x;
153		uint32_t y = threadIdx.y + blockDim.y * blockIdx.y;
154	
155		if (x >= resolution.x || y >= resolution.y) {
156			return;
157		}
158	
159		uint32_t idx = x + resolution.x * y;
160	
161		const vec2 uv = positions[idx];
162		if (uv.x < 0.0f || uv.x > 1.0f || uv.y < 0.0f || uv.y > 1.0f) {
163			frame_buffer[idx] = vec4(0.0f);
164			return;
165		}
166	
167		vec3 color = colors[idx];
168	
169		if (!linear_colors) {
170			color = srgb_to_linear(color);
171		}
172	
173		frame_buffer[idx] = {color.x, color.y, color.z, 1.0f};
174	}
