176	template <typename T, uint32_t stride>
177	__global__ void eval_image_kernel_and_snap(
178		uint32_t n_elements,
179		const T* __restrict__ texture,
180		vec2* __restrict__ positions,
181		ivec2 resolution,
182		float* __restrict__ result,
183		bool snap_to_pixel_centers,
184		bool linear_colors
185	) {
186		uint32_t i = blockIdx.x * blockDim.x + threadIdx.x;
187		if (i >= n_elements) {
188			return;
189		}
190	
191		uint32_t output_idx = i * stride;
192	
193		vec2 pos = positions[i];
194	
195		auto read_val = [&](int x, int y) {
196			auto val = ((tvec<T, 4>*)texture)[y * resolution.x + x];
197			vec4 result{(float)val[0], (float)val[1], (float)val[2], (float)val[3]};
198			if (!linear_colors) {
199				result.rgb() = linear_to_srgb(result.rgb());
200			}
201			return result;
202		};
203	
204		vec4 val;
205		if (snap_to_pixel_centers) {
206			ivec2 pos_int = floor(pos * vec2(resolution));
207			positions[i] = (vec2(pos_int) + 0.5f) / vec2(resolution);
208			pos_int = clamp(pos_int, 0, resolution - 1);
209			val = read_val(pos_int.x, pos_int.y);
210		} else {
211			pos = clamp(pos * vec2(resolution) - 0.5f, 0.0f, vec2(resolution) - (1.0f + 1e-4f));
212	
213			const ivec2 pos_int = pos;
214			const vec2 weight = pos - vec2(pos_int);
215	
216			const ivec2 idx = clamp(pos_int, 0, resolution - 2);
217	
218			val = (1 - weight.x) * (1 - weight.y) * read_val(idx.x, idx.y) + (weight.x) * (1 - weight.y) * read_val(idx.x + 1, idx.y) +
219				(1 - weight.x) * (weight.y) * read_val(idx.x, idx.y + 1) + (weight.x) * (weight.y) * read_val(idx.x + 1, idx.y + 1);
220		}
221	
222		result[output_idx + 0] = val.x;
223		result[output_idx + 1] = val.y;
224		result[output_idx + 2] = val.z;
225	
226		for (uint32_t i = 3; i < stride; ++i) {
227			result[output_idx + i] = 1;
228		}
229	}
