231	void Testbed::train_image(size_t target_batch_size, bool get_loss_scalar, cudaStream_t stream) {
232		const uint32_t n_output_dims = 3;
233		const uint32_t n_input_dims = 2;
234	
235		const uint32_t batch_size = (uint32_t)target_batch_size;
236	
237		const uint32_t n_elements = batch_size;
238		m_image.training.positions.enlarge(n_elements);
239		m_image.training.targets.enlarge(n_elements);
240	
241		auto generate_training_data = [&]() {
242			if (m_image.random_mode == ERandomMode::Halton) {
243				linear_kernel(halton23_kernel, 0, stream, n_elements, (size_t)batch_size * m_training_step, m_image.training.positions.data());
244			} else if (m_image.random_mode == ERandomMode::Sobol) {
245				linear_kernel(
246					sobol2_kernel, 0, stream, n_elements, (size_t)batch_size * m_training_step, m_seed, m_image.training.positions.data()
247				);
248			} else {
249				generate_random_uniform<float>(stream, m_rng, n_elements * n_input_dims, (float*)m_image.training.positions.data());
250				if (m_image.random_mode == ERandomMode::Stratified) {
251					uint32_t log2_batch_size = 0;
252					if (!is_pot(batch_size, &log2_batch_size)) {
253						tlog::warning() << "Can't stratify a non-pot batch size";
254					} else if (log2_batch_size % 2 != 0) {
255						tlog::warning() << "Can't stratify a non-square batch size";
256					} else {
257						linear_kernel(stratify2_kernel, 0, stream, n_elements, log2_batch_size, m_image.training.positions.data());
258					}
259				}
260			}
261	
262			if (m_image.type == EDataType::Float) {
263				linear_kernel(
264					eval_image_kernel_and_snap<float, 3>,
265					0,
266					stream,
267					n_elements,
268					(float*)m_image.data.data(),
269					m_image.training.positions.data(),
270					m_image.resolution,
271					(float*)m_image.training.targets.data(),
272					m_image.training.snap_to_pixel_centers,
273					m_image.training.linear_colors
274				);
275			} else {
276				linear_kernel(
277					eval_image_kernel_and_snap<__half, 3>,
278					0,
279					stream,
280					n_elements,
281					(__half*)m_image.data.data(),
282					m_image.training.positions.data(),
283					m_image.resolution,
284					(float*)m_image.training.targets.data(),
285					m_image.training.snap_to_pixel_centers,
286					m_image.training.linear_colors
287				);
288			}
289		};
290	
291		generate_training_data();
292	
293		GPUMatrix<float> training_batch_matrix((float*)(m_image.training.positions.data()), n_input_dims, batch_size);
294		GPUMatrix<float> training_target_matrix((float*)(m_image.training.targets.data()), n_output_dims, batch_size);
295	
296		auto ctx = m_trainer->training_step(stream, training_batch_matrix, training_target_matrix);
297		if (get_loss_scalar) {
298			m_loss_scalar.update(m_trainer->loss(stream, *ctx));
299		}
300	
301		m_training_step++;
302	}
