304	void Testbed::render_image(
305		cudaStream_t stream,
306		const CudaRenderBufferView& render_buffer,
307		const vec2& focal_length,
308		const mat4x3& camera_matrix,
309		const vec2& screen_center,
310		const Foveation& foveation,
311		const Lens& lens,
312		int visualized_dimension
313	) {
314		auto res = render_buffer.resolution;
315	
316		// Make sure we have enough memory reserved to render at the requested resolution
317		size_t n_pixels = (size_t)res.x * res.y;
318		uint32_t n_elements = next_multiple((uint32_t)n_pixels, BATCH_SIZE_GRANULARITY);
319		m_image.render_coords.enlarge(n_elements);
320		m_image.render_out.enlarge(n_elements);
321	
322		float plane_z = m_slice_plane_z + m_scale;
323		float aspect = (float)m_image.resolution.y / (float)m_image.resolution.x;
324	
325		// Generate 2D coords at which to query the network
326		const dim3 threads = {16, 8, 1};
327		const dim3 blocks = {div_round_up((uint32_t)res.x, threads.x), div_round_up((uint32_t)res.y, threads.y), 1};
328		init_image_coords<<<blocks, threads, 0, stream>>>(
329			render_buffer.spp,
330			m_image.render_coords.data(),
331			render_buffer.depth_buffer,
332			res,
333			aspect,
334			focal_length,
335			camera_matrix,
336			screen_center,
337			m_parallax_shift,
338			m_snap_to_pixel_centers,
339			plane_z,
340			m_aperture_size,
341			foveation,
342			render_buffer.hidden_area_mask ? render_buffer.hidden_area_mask->const_view() : Buffer2DView<const uint8_t>{},
343			lens
344		);
345	
346		// Obtain colors for each 2D coord
347		if (m_image.type == EDataType::Float) {
348			linear_kernel(
349				eval_image_kernel_and_snap<float, 3>,
350				0,
351				stream,
352				n_elements,
353				(float*)m_image.data.data(),
354				m_image.render_coords.data(),
355				m_image.resolution,
356				(float*)m_image.render_out.data(),
357				m_image.training.snap_to_pixel_centers,
358				m_image.training.linear_colors
359			);
360		} else {
361			linear_kernel(
362				eval_image_kernel_and_snap<__half, 3>,
363				0,
364				stream,
365				n_elements,
366				(__half*)m_image.data.data(),
367				m_image.render_coords.data(),
368				m_image.resolution,
369				(float*)m_image.render_out.data(),
370				m_image.training.snap_to_pixel_centers,
371				m_image.training.linear_colors
372			);
373		}
374	
375		if (!m_render_ground_truth) {
376			if (visualized_dimension >= 0) {
377				GPUMatrix<float> positions_matrix((float*)m_image.render_coords.data(), 2, n_elements);
378				GPUMatrix<float> colors_matrix((float*)m_image.render_out.data(), 3, n_elements);
379				m_network->visualize_activation(stream, m_visualized_layer, visualized_dimension, positions_matrix, colors_matrix);
380			} else {
381				GPUMatrix<float> positions_matrix((float*)m_image.render_coords.data(), 2, n_elements);
382				GPUMatrix<float> colors_matrix((float*)m_image.render_out.data(), 3, n_elements);
383				m_network->inference(stream, positions_matrix, colors_matrix);
384			}
385		}
386	
387		// Splat colors to render texture
388		shade_kernel_image<<<blocks, threads, 0, stream>>>(
389			res, m_image.render_coords.data(), m_image.render_out.data(), render_buffer.frame_buffer, m_image.training.linear_colors
390		);
391	}
