393	void Testbed::load_image(const fs::path& data_path) {
394		if (equals_case_insensitive(data_path.extension(), "exr")) {
395			load_exr_image(data_path);
396		} else if (equals_case_insensitive(data_path.extension(), "bin")) {
397			load_binary_image(data_path);
398		} else {
399			load_stbi_image(data_path);
400		}
401	
402		m_aabb = m_render_aabb = BoundingBox{vec3(0.0f), vec3(1.0f)};
403		m_render_aabb_to_local = mat3::identity();
404	
405		tlog::success() << "Loaded a " << (m_image.type == EDataType::Half ? "half" : "full") << "-precision image with "
406						<< m_image.resolution.x << "x" << m_image.resolution.y << " pixels.";
407	}
