409	void Testbed::load_exr_image(const fs::path& data_path) {
410		if (!data_path.exists()) {
411			throw std::runtime_error{fmt::format("Image file '{}' does not exist.", data_path.str())};
412		}
413	
414		tlog::info() << "Loading EXR image from " << data_path;
415	
416		// First step: load an image that we'd like to learn
417		GPUMemory<float> image = load_exr_gpu(data_path, &m_image.resolution.x, &m_image.resolution.y);
418		m_image.data.resize(image.size() * sizeof(float));
419		CUDA_CHECK_THROW(cudaMemcpy(m_image.data.data(), image.data(), image.size() * sizeof(float), cudaMemcpyDeviceToDevice));
420	
421		m_image.type = EDataType::Float;
422	}
