439	void Testbed::load_binary_image(const fs::path& data_path) {
440		if (!data_path.exists()) {
441			throw std::runtime_error{fmt::format("Image file '{}' does not exist.", data_path.str())};
442		}
443	
444		tlog::info() << "Loading binary image from " << data_path;
445	
446		std::ifstream f{native_string(data_path), std::ios::in | std::ios::binary};
447		f.read(reinterpret_cast<char*>(&m_image.resolution.y), sizeof(int));
448		f.read(reinterpret_cast<char*>(&m_image.resolution.x), sizeof(int));
449	
450		size_t n_pixels = (size_t)m_image.resolution.x * m_image.resolution.y;
451		m_image.data.resize(n_pixels * 4 * sizeof(__half));
452	
453		std::vector<__half> image(n_pixels * 4);
454		f.read(reinterpret_cast<char*>(image.data()), sizeof(__half) * image.size());
455		CUDA_CHECK_THROW(cudaMemcpy(m_image.data.data(), image.data(), image.size() * sizeof(__half), cudaMemcpyHostToDevice));
456		m_image.type = EDataType::Half;
457	}
