459	__global__ void image_coords_from_idx(const uint32_t n_elements, uint32_t offset, vec2* __restrict__ pos, ivec2 resolution) {
460		uint32_t i = blockIdx.x * blockDim.x + threadIdx.x;
461		if (i >= n_elements) {
462			return;
463		}
464	
465		const uint32_t idx = i + offset;
466	
467		int x = idx % resolution.x;
468		int y = idx / resolution.x;
469	
470		pos[i] = (vec2(clamp(ivec2{x, y}, 0, resolution - 1)) + 0.5f) / vec2(resolution);
471	}
