473	__global__ void image_mse_kernel(
474		const uint32_t n_elements, const vec3* __restrict__ target, const vec3* __restrict__ prediction, float* __restrict__ result, bool quantize_to_byte
475	) {
476		uint32_t i = blockIdx.x * blockDim.x + threadIdx.x;
477		if (i >= n_elements) {
478			return;
479		}
480	
481		vec3 pred = prediction[i];
482		if (quantize_to_byte) {
483			pred = vec3(clamp(ivec3(pred * 255.0f + 0.5f), 0, 255)) / 255.0f;
484		}
485	
486		const vec3 diff = target[i] - pred;
487		result[i] = dot(diff, diff) / 3.0f;
488	}
