490	float Testbed::compute_image_mse(bool quantize_to_byte) {
491		const uint32_t n_output_dims = 3;
492		const uint32_t n_input_dims = 2;
493	
494		// Auxiliary matrices for training
495		const uint32_t n_elements = product(m_image.resolution);
496		const uint32_t max_batch_size = 1u << 20;
497	
498		GPUMemory<float> se(n_elements);
499		GPUMemory<vec2> pos(max_batch_size);
500		GPUMemory<vec3> targets(max_batch_size);
501		GPUMemory<vec3> predictions(max_batch_size);
502		const uint32_t n_batches = div_round_up(n_elements, max_batch_size);
503		for (uint32_t i = 0; i < n_batches; ++i) {
504			uint32_t offset = i * max_batch_size;
505			uint32_t batch_size = (std::min(max_batch_size, n_elements - offset) + 255u) & (~255u);
506	
507			GPUMatrix<float> pos_matrix((float*)(pos.data()), n_input_dims, batch_size);
508			GPUMatrix<float> targets_matrix((float*)(targets.data()), n_output_dims, batch_size);
509			GPUMatrix<float> predictions_matrix((float*)(predictions.data()), n_output_dims, batch_size);
510	
511			linear_kernel(image_coords_from_idx, 0, nullptr, batch_size, offset, pos.data(), m_image.resolution);
512	
513			if (m_image.type == EDataType::Float) {
514				linear_kernel(
515					eval_image_kernel_and_snap<float, 3>,
516					0,
517					nullptr,
518					batch_size,
519					(float*)m_image.data.data(),
520					pos.data(),
521					m_image.resolution,
522					(float*)targets.data(),
523					true,
524					m_image.training.linear_colors
525				);
526			} else {
527				linear_kernel(
528					eval_image_kernel_and_snap<__half, 3>,
529					0,
530					nullptr,
531					batch_size,
532					(__half*)m_image.data.data(),
533					pos.data(),
534					m_image.resolution,
535					(float*)targets.data(),
536					true,
537					m_image.training.linear_colors
538				);
539			}
540	
541			m_network->inference(pos_matrix, predictions_matrix);
542	
543			linear_kernel(image_mse_kernel, 0, nullptr, batch_size, targets.data(), predictions.data(), se.data() + offset, quantize_to_byte);
544		}
545	
546		return reduce_sum(se.data(), n_elements, nullptr) / n_elements;
547	}
